            dp[j][1] = d

    for j in range(n):
        pos_j = j + 1
        d_j = pos_j - a[j]
        if d_j < 0:
            continue
        for prev in range(j):
            pos_prev = prev + 1
            d_prev = pos_prev - a[prev]
            if d_prev < 0:
                continue
            # check constraints
            if d_j < d_prev:
                continue
            if d_j - d_prev > pos_j - pos_prev - 1:
                continue
